2719	    // Assumption is that all mboards use the same link
2720	    // and that the rate sum is evenly distributed among the mboards
2721	    bool _check_link_rate(const stream_args_t& args, bool is_tx)
2722	    {
2723	        bool link_rate_is_ok    = true;
2724	        size_t bytes_per_sample = convert::get_bytes_per_item(
2725	            args.otw_format.empty() ? "sc16" : args.otw_format);
2726	        double max_link_rate = 0;
2727	        double sum_rate      = 0;
2728	        for (const size_t chan : args.channels) {
2729	            mboard_chan_pair mcp = is_tx ? tx_chan_to_mcp(chan) : rx_chan_to_mcp(chan);
2730	            if (_tree->exists(mb_root(mcp.mboard) / "link_max_rate")) {
2731	                max_link_rate = std::max(max_link_rate,
2732	                    _tree->access<double>(mb_root(mcp.mboard) / "link_max_rate").get());
2733	            }
2734	            sum_rate += is_tx ? get_tx_rate(chan) : get_rx_rate(chan);
2735	        }
2736	        sum_rate /= get_num_mboards();
2737	        if (max_link_rate > 0 and (max_link_rate / bytes_per_sample) < sum_rate) {
2738	            UHD_LOGGER_WARNING("MULTI_USRP")
2739	                << boost::format("The total sum of rates (%f MSps on %u channels) "
2740	                                 "exceeds the maximum capacity of the connection.\n"
2741	                                 "This can cause %s.")
2742	                       % (sum_rate / 1e6) % args.channels.size()
2743	                       % (is_tx ? "underruns (U)" : "overflows (O)");
2744	            link_rate_is_ok = false;
2745	        }
2746	
2747	        return link_rate_is_ok;
2748	    }
